var alertNames = function(keyName, keyTime) {
    const times = new Map();
    for (let i = 0; i < keyName.length; i++) {
        const name = keyName[i];
        const [h, m] = keyTime[i].split(':').map(Number);
        const mins = h * 60 + m;
        if (!times.has(name)) times.set(name, []);
        times.get(name).push(mins);
    }
    const result = [];
    for (const [name, lst] of times) {
        lst.sort((a, b) => a - b);
        for (let i = 0; i + 2 < lst.length; i++) {
            if (lst[i + 2] - lst[i] <= 60) {
                result.push(name);
                break;
            }
        }
    }
    result.sort();
    return result;
};
